1	//! Saga 13 step 001: token embedding layer.
2	//!
3	//! `embed(vocab_size, d_model, seed)` constructs a `Value::Model` whose
4	//! single trainable parameter is a `[vocab, d_model]` lookup table.
5	//! `apply(emb, tokens)` gathers rows from the table by integer token
6	//! ids: input `[N]` -> output `[N, d_model]`. Gradients flow back into
7	//! the table through the autograd tape so `adam(loss, emb, ...)`
8	//! trains it like any other layer.
9	
10	use mlpl_array::{DenseArray, Shape};
11	use mlpl_eval::{Environment, eval_program, model_params};
12	use mlpl_parser::{lex, parse};
13	
14	fn arr(dims: Vec<usize>, data: Vec<f64>) -> DenseArray {
15	    DenseArray::new(Shape::new(dims), data).unwrap()
16	}
17	
18	fn run(src: &str, env: &mut Environment) -> DenseArray {
19	    eval_program(&parse(&lex(src).unwrap()).unwrap(), env).unwrap()
20	}
21	
22	#[test]
23	fn embed_creates_model_with_one_table_parameter() {
24	    let mut env = Environment::new();
25	    eval_program(
26	        &parse(&lex("E = embed(5, 3, 7)").unwrap()).unwrap(),
27	        &mut env,
28	    )
29	    .unwrap();
30	    let names = model_params(&env, "E").expect("E is a registered model");
31	    assert_eq!(names.len(), 1, "embedding owns a single table parameter");
32	    let table = env.get(&names[0]).expect("table bound");
33	    assert_eq!(table.shape().dims(), &[5, 3]);
34	    assert!(
35	        env.is_param(&names[0]),
36	        "table must be tracked as trainable"
37	    );
38	}
39	
40	#[test]
41	fn apply_embed_gathers_rows_by_token_id() {
42	    // Build an embedding then overwrite the table with a known matrix.
43	    let mut env = Environment::new();
44	    eval_program(
45	        &parse(&lex("E = embed(5, 3, 1)").unwrap()).unwrap(),
46	        &mut env,
47	    )
48	    .unwrap();
49	    let names = model_params(&env, "E").unwrap();
50	    let table = arr(
51	        vec![5, 3],
52	        vec![
53	            0.0, 0.1, 0.2, // row 0
54	            1.0, 1.1, 1.2, // row 1
55	            2.0, 2.1, 2.2, // row 2
56	            3.0, 3.1, 3.2, // row 3
57	            4.0, 4.1, 4.2, // row 4
58	        ],
59	    );
60	    env.set(names[0].clone(), table);
61	    env.set("toks".into(), arr(vec![3], vec![0.0, 2.0, 4.0]));
62	    let out = run("apply(E, toks)", &mut env);
63	    assert_eq!(out.shape().dims(), &[3, 3]);
64	    assert_eq!(out.data(), &[0.0, 0.1, 0.2, 2.0, 2.1, 2.2, 4.0, 4.1, 4.2]);
65	}
66	
67	#[test]
68	fn apply_embed_handles_repeated_tokens() {
69	    let mut env = Environment::new();
70	    eval_program(
71	        &parse(&lex("E = embed(3, 2, 2)").unwrap()).unwrap(),
72	        &mut env,
73	    )
74	    .unwrap();
75	    let names = model_params(&env, "E").unwrap();
76	    env.set(
77	        names[0].clone(),
78	        arr(vec![3, 2], vec![10.0, 20.0, 30.0, 40.0, 50.0, 60.0]),
79	    );
80	    env.set("toks".into(), arr(vec![4], vec![1.0, 1.0, 0.0, 1.0]));
81	    let out = run("apply(E, toks)", &mut env);
82	    assert_eq!(out.shape().dims(), &[4, 2]);
83	    assert_eq!(
84	        out.data(),
85	        &[30.0, 40.0, 30.0, 40.0, 10.0, 20.0, 30.0, 40.0]
86	    );
87	}
88	
89	#[test]
90	fn apply_embed_rejects_out_of_range_token() {
91	    let mut env = Environment::new();
92	    eval_program(
93	        &parse(&lex("E = embed(3, 2, 0)").unwrap()).unwrap(),
94	        &mut env,
95	    )
96	    .unwrap();
97	    env.set("toks".into(), arr(vec![2], vec![0.0, 5.0])); // 5 >= vocab 3
98	    let result = eval_program(&parse(&lex("apply(E, toks)").unwrap()).unwrap(), &mut env);
99	    assert!(result.is_err(), "out-of-range token must surface an error");
100	    let msg = format!("{}", result.unwrap_err());
101	    assert!(
102	        msg.contains("token") || msg.contains("vocab") || msg.contains("range"),
103	        "error should mention token / vocab / range, got: {msg}"
104	    );
105	}
106	
107	#[test]
108	fn grad_through_apply_embed_matches_one_hot_form() {
109	    // grad(loss, table) for an embedding lookup must equal grad of the
110	    // hand-written `O @ table` form, where O is the [N, V] one-hot of
111	    // the token ids. This is the gradcheck for the embedding layer.
112	    let mut env = Environment::new();
113	    let setup = "\
114	        E = embed(4, 2, 5)\n\
115	        toks = [0.0, 2.0, 1.0, 2.0]\n\
116	        ONE = [[1.0, 0.0, 0.0, 0.0], \
117	               [0.0, 0.0, 1.0, 0.0], \
118	               [0.0, 1.0, 0.0, 0.0], \
119	               [0.0, 0.0, 1.0, 0.0]]\n";
120	    eval_program(&parse(&lex(setup).unwrap()).unwrap(), &mut env).unwrap();
121	    let names = model_params(&env, "E").unwrap();
122	    let table = names[0].clone();
123	
124	    let g_apply = run(&format!("grad(sum(apply(E, toks)), {table})"), &mut env);
125	    let g_hand = run(
126	        &format!("grad(sum(matmul(ONE, {table})), {table})"),
127	        &mut env,
128	    );
129	    assert_eq!(g_apply.shape(), g_hand.shape());
130	    for (a, b) in g_apply.data().iter().zip(g_hand.data().iter()) {
131	        assert!((a - b).abs() < 1e-10, "grad mismatch: {a} vs {b}");
132	    }
133	    // Repeated token id 2 must accumulate: row 2 of the gradient should
134	    // be twice the contribution of a single row.
135	    let g = g_apply.data();
136	    assert!((g[2 * 2] - 2.0).abs() < 1e-10, "row 2 col 0 expected 2.0");
137	    assert!(
138	        (g[2 * 2 + 1] - 2.0).abs() < 1e-10,
139	        "row 2 col 1 expected 2.0"
140	    );
141	}
142	
143	#[test]
144	fn adam_step_reduces_embedding_loss() {
145	    // sum(apply(E, toks) * apply(E, toks)) is a quadratic in the rows
146	    // of the table touched by `toks` (rows 0, 1, 2). 50 Adam steps must
147	    // shrink those rows toward zero. Row 3 is untouched and so its
148	    // norm should be unchanged. We can't read sum() outside grad/opt,
149	    // so we verify by inspecting the table directly after training.
150	    let mut env = Environment::new();
151	    eval_program(
152	        &parse(&lex("E = embed(4, 2, 11)").unwrap()).unwrap(),
153	        &mut env,
154	    )
155	    .unwrap();
156	    let names = model_params(&env, "E").unwrap();
157	    let table_name = names[0].clone();
158	    env.set(
159	        table_name.clone(),
160	        arr(vec![4, 2], vec![1.0, -1.0, 0.5, 0.5, -0.5, 0.25, 9.0, -9.0]),
161	    );
162	    env.set("toks".into(), arr(vec![3], vec![0.0, 1.0, 2.0]));
163	
164	    let row_norm = |t: &DenseArray, r: usize| -> f64 {
165	        let d = t.data();
166	        (d[r * 2] * d[r * 2] + d[r * 2 + 1] * d[r * 2 + 1]).sqrt()
167	    };
168	    let table0 = env.get(&table_name).unwrap().clone();
169	    let n0_0 = row_norm(&table0, 0);
170	    let n0_1 = row_norm(&table0, 1);
171	    let n0_2 = row_norm(&table0, 2);
172	    let n0_3 = row_norm(&table0, 3);
173	
174	    eval_program(
175	        &parse(&lex(
176	            "train 50 { adam(sum(apply(E, toks) * apply(E, toks)), E, 0.05, 0.9, 0.999, 0.00000001) }",
177	        ).unwrap()).unwrap(),
178	        &mut env,
179	    ).unwrap();
180	
181	    let table1 = env.get(&table_name).unwrap().clone();
182	    let n1_0 = row_norm(&table1, 0);
183	    let n1_1 = row_norm(&table1, 1);
184	    let n1_2 = row_norm(&table1, 2);
185	    let n1_3 = row_norm(&table1, 3);
186	
187	    assert!(n1_0 < n0_0, "row 0 expected to shrink, {n0_0} -> {n1_0}");
188	    assert!(n1_1 < n0_1, "row 1 expected to shrink, {n0_1} -> {n1_1}");
189	    assert!(n1_2 < n0_2, "row 2 expected to shrink, {n0_2} -> {n1_2}");
190	    assert!(
191	        (n1_3 - n0_3).abs() < 1e-12,
192	        "row 3 (untouched by toks) must be unchanged, {n0_3} -> {n1_3}"
193	    );
194	}
195	
196	#[test]
197	fn describe_embed_renders_vocab_and_d() {
198	    // :describe should pretty-print embedding shape parameters.
199	    let mut env = Environment::new();
200	    eval_program(
201	        &parse(&lex("E = embed(7, 4, 0)").unwrap()).unwrap(),
202	        &mut env,
203	    )
204	    .unwrap();
205	    let desc = mlpl_eval::inspect(&env, ":describe E").expect("inspect returns a String");
206	    assert!(
207	        desc.contains("embed[vocab=7, d=4]"),
208	        ":describe E should include 'embed[vocab=7, d=4]', got:\n{desc}"
209	    );
210	}
