1	//! AST-walking evaluator.
2	
3	use mlpl_array::{ArrayError, DenseArray, Shape};
4	use mlpl_autograd::{Tape, Tensor};
5	use mlpl_parser::{Expr, TensorCtorKind};
6	use mlpl_trace::{Trace, TraceEvent, TraceValue};
7	
8	use crate::env::Environment;
9	use crate::error::EvalError;
10	use crate::eval_ops::{
11	    eval_analysis_helper, eval_array_lit, eval_binop, eval_fncall, eval_svg, labeled_shape_of,
12	};
13	use crate::value::Value;
14	
15	/// Evaluate a program (list of statements). Returns the last result as an array.
16	///
17	/// If the final value is a string, returns `EvalError::ExpectedArray`.
18	/// Use `eval_program_value` to handle both arrays and strings.
19	pub fn eval_program(stmts: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
20	    eval_program_value(stmts, env)?.into_array()
21	}
22	
23	/// Evaluate a program and return the final value (array or string).
24	pub fn eval_program_value(stmts: &[Expr], env: &mut Environment) -> Result<Value, EvalError> {
25	    run_program(stmts, env, None)
26	}
27	
28	/// Evaluate a program with tracing enabled. Returns the final array.
29	pub fn eval_program_traced(
30	    stmts: &[Expr],
31	    env: &mut Environment,
32	    trace: &mut Trace,
33	) -> Result<DenseArray, EvalError> {
34	    run_program(stmts, env, Some(trace))?.into_array()
35	}
36	
37	fn run_program(
38	    stmts: &[Expr],
39	    env: &mut Environment,
40	    mut trace: Option<&mut Trace>,
41	) -> Result<Value, EvalError> {
42	    if stmts.is_empty() {
43	        return Err(EvalError::EmptyInput);
44	    }
45	    let mut result = None;
46	    for stmt in stmts {
47	        result = Some(eval_expr(stmt, env, &mut trace)?);
48	    }
49	    result.ok_or(EvalError::EmptyInput)
50	}
51	
52	pub(crate) fn eval_expr(
53	    expr: &Expr,
54	    env: &mut Environment,
55	    trace: &mut Option<&mut Trace>,
56	) -> Result<Value, EvalError> {
57	    if let Expr::StrLit(s, _) = expr {
58	        return Ok(Value::Str(s.clone()));
59	    }
60	    if let Expr::Ident(name, _) = expr
61	        && let Some(s) = env.get_string(name)
62	    {
63	        return Ok(Value::Str(s.clone()));
64	    }
65	    if let Expr::FnCall { name, args, .. } = expr
66	        && name == "svg"
67	    {
68	        return eval_svg(args, env, trace).map(Value::Str);
69	    }
70	    if let Expr::FnCall { name, args, span } = expr
71	        && name == "grad"
72	    {
73	        let result = crate::grad::eval_grad(args, env)?;
74	        if let Some(t) = trace.as_mut() {
75	            let seq = t.events().len() as u64;
76	            t.push(TraceEvent {
77	                seq,
78	                op: "grad".into(),
79	                span: *span,
80	                inputs: vec![],
81	                output: TraceValue::from_array(&result),
82	            });
83	        }
84	        return Ok(Value::Array(result));
85	    }
86	    if let Expr::FnCall { name, args, .. } = expr {
87	        // Model-constructor dispatch -- each builds a ModelSpec from
88	        // its args and returns Value::Model. Kept as a single match so
89	        // the eval entrypoint stays under its file LOC budget.
90	        let model = match name.as_str() {
91	            "linear" => Some(crate::model_dispatch::eval_linear(args, env)),
92	            "embed" => Some(crate::model_dispatch::eval_embedding(args, env)),
93	            "chain" => Some(crate::model_dispatch::eval_chain(args, env)),
94	            "residual" => Some(crate::model_dispatch::eval_residual(args, env)),
95	            "rms_norm" => Some(crate::model_dispatch::eval_rms_norm(args, env)),
96	            "attention" => Some(crate::model_dispatch::eval_attention(args, env)),
97	            _ => None,
98	        };
99	        if let Some(m) = model {
100	            return Ok(Value::Model(m?));
101	        }
102	    }
103	    if let Expr::FnCall { name, args, .. } = expr
104	        && let Some(kind) = crate::model_dispatch::activation_kind(name)
105	    {
106	        if !args.is_empty() {
107	            return Err(EvalError::BadArity {
108	                func: name.into(),
109	                expected: 0,
110	                got: args.len(),
111	            });
112	        }
113	        return Ok(Value::Model(crate::model::ModelSpec::Activation(kind)));
114	    }
115	    if let Expr::FnCall { name, args, .. } = expr
116	        && name == "apply"
117	    {
118	        let result = crate::model_dispatch::eval_apply(args, env, trace)?;
119	        return Ok(Value::Array(result));
120	    }
121	    if let Expr::FnCall { name, args, .. } = expr
122	        && name == "reshape_labeled"
123	    {
124	        if args.len() != 3 {
125	            return Err(EvalError::BadArity {
126	                func: "reshape_labeled".into(),
127	                expected: 3,
128	                got: args.len(),
129	            });
130	        }
131	        let Expr::ArrayLit(label_elems, _) = &args[2] else {
132	            return Err(EvalError::Unsupported(
133	                "reshape_labeled: third argument must be a bracketed list of string literals"
134	                    .into(),
135	            ));
136	        };
137	        let mut labels: Vec<Option<String>> = Vec::with_capacity(label_elems.len());
138	        for e in label_elems {
139	            let Expr::StrLit(s, _) = e else {
140	                return Err(EvalError::Unsupported(
141	                    "reshape_labeled: axis names must be string literals".into(),
142	                ));
143	            };
144	            labels.push(Some(s.clone()));
145	        }
146	        let source = eval_expr(&args[0], env, trace)?.into_array()?;
147	        let shape_arr = eval_expr(&args[1], env, trace)?.into_array()?;
148	        let dims: Vec<usize> = shape_arr.data().iter().map(|&d| d as usize).collect();
149	        let reshaped = source.reshape(Shape::new(dims))?;
150	        let labeled = reshaped.with_labels(labels)?;
151	        return Ok(Value::Array(labeled));
152	    }
153	    if let Expr::FnCall { name, args, .. } = expr
154	        && let Some(r) = crate::tokenizer::dispatch(name, args, env, trace)
155	    {
156	        return r;
157	    }
158	    if let Expr::FnCall { name, args, .. } = expr
159	        && name == "compare"
160	    {
161	        return crate::experiment::dispatch_compare(args, env);
162	    }
163	    if let Expr::FnCall { name, args, .. } = expr
164	        && (name == "load" || name == "load_preloaded")
165	    {
166	        if args.len() != 1 {
167	            return Err(EvalError::BadArity {
168	                func: name.clone(),
169	                expected: 1,
170	                got: args.len(),
171	            });
172	        }
173	        let Expr::StrLit(path, _) = &args[0] else {
174	            return Err(EvalError::Unsupported(format!(
175	                "{name}: argument must be a string literal"
176	            )));
177	        };
178	        return if name == "load" {
179	            crate::loader::eval_load(env, path)
180	        } else {
181	            crate::loader::eval_load_preloaded(path)
182	        };
183	    }
184	    if let Expr::FnCall { name, args, span } = expr
185	        && name == "matmul"
186	        && args.len() == 2
187	    {
188	        let l = eval_expr(&args[0], env, trace)?.into_array()?;
189	        let r = eval_expr(&args[1], env, trace)?.into_array()?;
190	        let result = match l.matmul(&r) {
191	            Ok(a) => a,
192	            Err(ArrayError::ShapeMismatch { .. } | ArrayError::LabelMismatch { .. }) => {
193	                return Err(EvalError::ShapeMismatch {
194	                    op: "matmul".into(),
195	                    expected: labeled_shape_of(&l),
196	                    actual: labeled_shape_of(&r),
197	                });
198	            }
199	            Err(e) => return Err(e.into()),
200	        };
201	        if let Some(t) = trace.as_mut() {
202	            let seq = t.events().len() as u64;
203	            t.push(TraceEvent {
204	                seq,
205	                op: "matmul".into(),
206	                span: *span,
207	                inputs: vec![TraceValue::from_array(&l), TraceValue::from_array(&r)],
208	                output: TraceValue::from_array(&result),
209	            });
210	        }
211	        return Ok(Value::Array(result));
212	    }
213	    if let Expr::FnCall { name, args, .. } = expr
214	        && matches!(
215	            name.as_str(),
216	            "reduce_add" | "reduce_mul" | "argmax" | "softmax"
217	        )
218	        && args.len() == 2
219	        && let Expr::StrLit(axis_name, _) = &args[1]
220	    {
221	        let arr = eval_expr(&args[0], env, trace)?.into_array()?;
222	        let labels = arr.labels().ok_or_else(|| {
223	            EvalError::Unsupported(format!(
224	                "{name}: axis name \"{axis_name}\" requires a labeled array"
225	            ))
226	        })?;
227	        let axis = labels
228	            .iter()
229	            .position(|l| l.as_deref() == Some(axis_name.as_str()))
230	            .ok_or_else(|| {
231	                EvalError::Unsupported(format!(
232	                    "{name}: axis name \"{axis_name}\" not found in labels"
233	                ))
234	            })?;
235	        let axis_arr = DenseArray::from_scalar(axis as f64);
236	        let result = mlpl_runtime::call_builtin(name, vec![arr, axis_arr])?;
237	        return Ok(Value::Array(result));
238	    }
239	    if let Expr::FnCall { name, args, .. } = expr
240	        && (name == "label" || name == "relabel")
241	    {
242	        if args.len() != 2 {
243	            return Err(EvalError::BadArity {
244	                func: name.clone(),
245	                expected: 2,
246	                got: args.len(),
247	            });
248	        }
249	        let Expr::ArrayLit(label_elems, _) = &args[1] else {
250	            return Err(EvalError::Unsupported(format!(
251	                "{name}: second argument must be a bracketed list of string literals"
252	            )));
253	        };
254	        let mut labels: Vec<Option<String>> = Vec::with_capacity(label_elems.len());
255	        for e in label_elems {
256	            let Expr::StrLit(s, _) = e else {
257	                return Err(EvalError::Unsupported(format!(
258	                    "{name}: axis names must be string literals"
259	                )));
260	            };
261	            labels.push(Some(s.clone()));
262	        }
263	        let arr = eval_expr(&args[0], env, trace)?.into_array()?;
264	        let labeled = arr.with_labels(labels)?;
265	        return Ok(Value::Array(labeled));
266	    }
267	    if let Expr::FnCall { name, args, .. } = expr
268	        && name == "labels"
269	    {
270	        if args.len() != 1 {
271	            return Err(EvalError::BadArity {
272	                func: "labels".into(),
273	                expected: 1,
274	                got: args.len(),
275	            });
276	        }
277	        let arr = eval_expr(&args[0], env, trace)?.into_array()?;
278	        // Comma-join the per-axis labels, using an empty string for
279	        // positional axes. Saga 11.5 Phase 1 intentionally stops at
280	        // this stringly-typed encoding because MLPL has no
281	        // string-vector literal yet; Phase 2 introduces one alongside
282	        // the `label(x, [...])` builtin and can upgrade this return
283	        // type in lock-step. The current encoding is testable and
284	        // unambiguous for every rank >= 1: a rank-3 positional array
285	        // becomes `",,"`, a labeled rank-2 becomes `"seq,d_k"`, etc.
286	        // Rank-0 and rank-1-positional both render as `""`; the user
287	        // can call `rank(x)` to disambiguate.
288	        let parts: Vec<String> = match arr.labels() {
289	            Some(lbls) => lbls.iter().map(|l| l.clone().unwrap_or_default()).collect(),
290	            None => (0..arr.rank()).map(|_| String::new()).collect(),
291	        };
292	        return Ok(Value::Str(parts.join(",")));
293	    }
294	    if let Expr::FnCall { name, args, span } = expr
295	        && (name == "momentum_sgd" || name == "adam")
296	    {
297	        let result = if name == "momentum_sgd" {
298	            crate::grad::eval_momentum_sgd(args, env)?
299	        } else {
300	            crate::grad::eval_adam(args, env)?
301	        };
302	        if let Some(t) = trace.as_mut() {
303	            let seq = t.events().len() as u64;
304	            t.push(TraceEvent {
305	                seq,
306	                op: name.clone(),
307	                span: *span,
308	                inputs: vec![],
309	                output: TraceValue::from_array(&result),
310	            });
311	        }
312	        return Ok(Value::Array(result));
313	    }
314	    if let Expr::FnCall { name, args, .. } = expr
315	        && let Some(result) = eval_analysis_helper(name, args, env, trace)
316	    {
317	        return result.map(Value::Str);
318	    }
319	    let (op_name, inputs, result) = match expr {
320	        Expr::IntLit(n, _) => ("literal", vec![], DenseArray::from_scalar(*n as f64)),
321	        Expr::FloatLit(f, _) => ("literal", vec![], DenseArray::from_scalar(*f)),
322	        Expr::StrLit(_, _) => unreachable!(),
323	        Expr::Ident(name, _) => {
324	            let r = env
325	                .get(name)
326	                .cloned()
327	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
328	            ("ident", vec![], r)
329	        }
330	        Expr::ArrayLit(elems, _) => ("array_lit", vec![], eval_array_lit(elems, env, trace)?),
331	        Expr::UnaryNeg { operand, .. } => {
332	            let val = eval_expr(operand, env, trace)?.into_array()?;
333	            let r = DenseArray::from_scalar(-1.0).apply_binop(&val, |a, b| a * b)?;
334	            ("negate", vec![TraceValue::from_array(&val)], r)
335	        }
336	        Expr::Assign { name, value, .. } => {
337	            let is_param_ctor = matches!(
338	                value.as_ref(),
339	                Expr::TensorCtor {
340	                    kind: TensorCtorKind::Param,
341	                    ..
342	                }
343	            );
344	            let v = eval_expr(value, env, trace)?;
345	            match v {
346	                Value::Model(m) => {
347	                    env.models.insert(name.clone(), m);
348	                    let placeholder = DenseArray::from_scalar(0.0);
349	                    ("assign_model", vec![], placeholder)
350	                }
351	                Value::Tokenizer(t) => {
352	                    env.set_tokenizer(name.clone(), t);
353	                    let placeholder = DenseArray::from_scalar(0.0);
354	                    ("assign_tokenizer", vec![], placeholder)
355	                }
356	                Value::Str(s) => {
357	                    env.set_string(name.clone(), s);
358	                    ("assign_string", vec![], DenseArray::from_scalar(0.0))
359	                }
360	                Value::Array(val) => {
361	                    env.set(name.clone(), val.clone());
362	                    if is_param_ctor {
363	                        env.mark_param(name);
364	                    }
365	                    ("assign", vec![TraceValue::from_array(&val)], val)
366	                }
367	            }
368	        }
369	        Expr::BinOp { op, lhs, rhs, .. } => eval_binop(op, lhs, rhs, env, trace)?,
370	        Expr::FnCall { name, args, .. } => eval_fncall(name, args, env, trace)?,
371	        Expr::TensorCtor { kind, shape, .. } => eval_tensor_ctor(*kind, shape, env, trace)?,
372	        Expr::Repeat { count, body, .. } => eval_repeat(count, body, env, trace)?,
373	        Expr::Train { count, body, .. } => eval_train(count, body, env, trace)?,
374	        Expr::For {
375	            binding,
376	            source,
377	            body,
378	            ..
379	        } => crate::eval_for::eval_for(binding, source, body, env, trace)?,
380	        Expr::Experiment { name, body, .. } => {
381	            crate::experiment::eval_experiment(name, body, env, trace)?
382	        }
383	    };
384	    if let Some(t) = trace.as_mut() {
385	        let seq = t.events().len() as u64;
386	        t.push(TraceEvent {
387	            seq,
388	            op: op_name.into(),
389	            span: expr.span(),
390	            inputs,
391	            output: TraceValue::from_array(&result),
392	        });
393	    }
394	    Ok(Value::Array(result))
395	}
396	
397	fn eval_tensor_ctor(
398	    kind: TensorCtorKind,
399	    shape: &[Expr],
400	    env: &mut Environment,
401	    trace: &mut Option<&mut Trace>,
402	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
403	    let mut dims = Vec::with_capacity(shape.len());
404	    for dim_expr in shape {
405	        let arr = eval_expr(dim_expr, env, trace)?.into_array()?;
406	        if arr.rank() != 0 {
407	            return Err(EvalError::InvalidShapeDim);
408	        }
409	        let v = arr.data()[0];
410	        if v < 0.0 || v.fract() != 0.0 {
411	            return Err(EvalError::InvalidShapeDim);
412	        }
413	        dims.push(v as usize);
414	    }
415	    let zeros = DenseArray::zeros(Shape::new(dims));
416	    // Construct an autograd Tensor on a fresh tape. Step 005 will
417	    // route this through a tape stored in the environment so that
418	    // operations on the resulting array are recorded; for now we
419	    // simply return the underlying zero-initialized array.
420	    let tape = Tape::new();
421	    let _tensor = match kind {
422	        TensorCtorKind::Param => Tensor::param(tape, zeros.clone()),
423	        TensorCtorKind::Tensor => Tensor::leaf(tape, zeros.clone(), false),
424	    };
425	    let op_name = match kind {
426	        TensorCtorKind::Param => "param_ctor",
427	        TensorCtorKind::Tensor => "tensor_ctor",
428	    };
429	    Ok((op_name, vec![], zeros))
430	}
431	
432	fn eval_repeat(
433	    count: &Expr,
434	    body: &[Expr],
435	    env: &mut Environment,
436	    trace: &mut Option<&mut Trace>,
437	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
438	    let n_arr = eval_expr(count, env, trace)?.into_array()?;
439	    if n_arr.rank() != 0 {
440	        return Err(EvalError::InvalidRepeatCount);
441	    }
442	    let n = n_arr.data()[0] as usize;
443	    let mut r = DenseArray::from_scalar(0.0);
444	    for _ in 0..n {
445	        for stmt in body {
446	            r = eval_expr(stmt, env, trace)?.into_array()?;
447	        }
448	    }
449	    Ok(("repeat", vec![], r))
450	}
451	
452	fn eval_train(
453	    count: &Expr,
454	    body: &[Expr],
455	    env: &mut Environment,
456	    trace: &mut Option<&mut Trace>,
457	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
458	    let n_arr = eval_expr(count, env, trace)?.into_array()?;
459	    if n_arr.rank() != 0 {
460	        return Err(EvalError::InvalidRepeatCount);
461	    }
462	    let n = n_arr.data()[0] as usize;
463	    let mut losses: Vec<f64> = Vec::with_capacity(n);
464	    let mut last = DenseArray::from_scalar(0.0);
465	    for i in 0..n {
466	        env.set("step".into(), DenseArray::from_scalar(i as f64));
467	        let mut step_val = DenseArray::from_scalar(0.0);
468	        for stmt in body {
469	            step_val = eval_expr(stmt, env, trace)?.into_array()?;
470	        }
471	        // Capture the body's final value as the per-step loss; if it
472	        // is non-scalar (e.g. a vector), reduce by mean for the loss
473	        // curve so callers can still rely on a scalar history.
474	        let scalar_loss = if step_val.rank() == 0 {
475	            step_val.data()[0]
476	        } else {
477	            let s: f64 = step_val.data().iter().sum();
478	            s / (step_val.data().len().max(1) as f64)
479	        };
480	        losses.push(scalar_loss);
481	        last = step_val;
482	    }
483	    let losses_arr = DenseArray::new(mlpl_array::Shape::new(vec![losses.len()]), losses)
484	        .expect("losses shape matches data");
485	    env.set("last_losses".into(), losses_arr);
486	    Ok(("train", vec![], last))
487	}
