1	//! Built-in function implementations.
2	
3	use mlpl_array::{DenseArray, Shape};
4	
5	use crate::error::RuntimeError;
6	use crate::math_builtins;
7	
8	macro_rules! check_arity {
9	    ($name:expr, $expected:expr, $args:expr) => {
10	        if $args.len() != $expected {
11	            return Err(RuntimeError::ArityMismatch {
12	                func: $name.into(),
13	                expected: $expected,
14	                got: $args.len(),
15	            });
16	        }
17	    };
18	}
19	
20	/// Dispatch a built-in function call by name.
21	pub fn call_builtin(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
22	    // Try math/constructor builtins first
23	    if let Some(result) = math_builtins::try_call(name, args.clone()) {
24	        return result;
25	    }
26	    if let Some(result) = crate::random_builtins::try_call(name, args.clone()) {
27	        return result;
28	    }
29	    if let Some(result) = crate::dataset_builtins::try_call(name, args.clone()) {
30	        return result;
31	    }
32	    if let Some(result) = crate::ml_builtins::try_call(name, args.clone()) {
33	        return result;
34	    }
35	    match name {
36	        "iota" => builtin_iota(name, args),
37	        "shape" => builtin_shape(name, args),
38	        "rank" => builtin_rank(name, args),
39	        "reshape" => builtin_reshape(name, args),
40	        "transpose" => builtin_transpose(name, args),
41	        "reduce_add" | "reduce_mul" => builtin_reduce(name, args),
42	        "argmax" => builtin_argmax(name, args),
43	        "dot" => {
44	            check_arity!(name, 2, args);
45	            Ok(args[0].dot(&args[1])?)
46	        }
47	        "matmul" => {
48	            check_arity!(name, 2, args);
49	            Ok(args[0].matmul(&args[1])?)
50	        }
51	        "grid" => crate::grid_builtin::builtin_grid(name, args),
52	        _ => Err(RuntimeError::UnknownFunction(name.into())),
53	    }
54	}
55	
56	fn builtin_iota(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
57	    check_arity!(name, 1, args);
58	    if args[0].rank() != 0 {
59	        return Err(RuntimeError::InvalidArgument {
60	            func: name.into(),
61	            reason: format!("expected scalar, got rank {}", args[0].rank()),
62	        });
63	    }
64	    let n = args[0].data()[0] as usize;
65	    let data: Vec<f64> = (0..n).map(|i| i as f64).collect();
66	    Ok(DenseArray::from_vec(data))
67	}
68	
69	fn builtin_shape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
70	    check_arity!(name, 1, args);
71	    let dims: Vec<f64> = args[0].shape().dims().iter().map(|&d| d as f64).collect();
72	    Ok(DenseArray::from_vec(dims))
73	}
74	
75	fn builtin_rank(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
76	    check_arity!(name, 1, args);
77	    Ok(DenseArray::from_scalar(args[0].rank() as f64))
78	}
79	
80	fn builtin_reshape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
81	    check_arity!(name, 2, args);
82	    let shape_data = args[1].data();
83	    let dims: Vec<usize> = shape_data.iter().map(|&d| d as usize).collect();
84	    Ok(args[0].reshape(Shape::new(dims))?)
85	}
86	
87	fn builtin_transpose(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
88	    check_arity!(name, 1, args);
89	    Ok(args[0].transpose())
90	}
91	
92	fn builtin_argmax(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
93	    if args.len() == 1 {
94	        // Flat argmax over all elements, returned as a scalar index.
95	        let data = args[0].data();
96	        if data.is_empty() {
97	            return Err(RuntimeError::InvalidArgument {
98	                func: name.into(),
99	                reason: "argmax of empty array".into(),
100	            });
101	        }
102	        let mut best_idx = 0usize;
103	        let mut best_val = data[0];
104	        for (i, &v) in data.iter().enumerate().skip(1) {
105	            if v > best_val {
106	                best_val = v;
107	                best_idx = i;
108	            }
109	        }
110	        return Ok(DenseArray::from_scalar(best_idx as f64));
111	    }
112	    if args.len() != 2 {
113	        return Err(RuntimeError::ArityMismatch {
114	            func: name.into(),
115	            expected: 2,
116	            got: args.len(),
117	        });
118	    }
119	    if args[1].rank() != 0 {
120	        return Err(RuntimeError::InvalidArgument {
121	            func: name.into(),
122	            reason: format!("axis must be scalar, got rank {}", args[1].rank()),
123	        });
124	    }
125	    let axis = args[1].data()[0] as usize;
126	    Ok(args[0].argmax_axis(axis)?)
