    //   col 1 (i=0, odd):  cos(pos / 10000^0)         = cos(pos)
    //   col 2 (i=1, even): sin(pos / 10000^(2/4))     = sin(pos / 100)
    //   col 3 (i=1, odd):  cos(pos / 10000^(2/4))     = cos(pos / 100)
    let mut env = Environment::new();
