1	//! Saga 13 step 002: sinusoidal positional encoding.
2	//!
3	//! `sinusoidal_encoding(seq_len, d_model)` returns a deterministic
4	//! `[seq_len, d_model]` float array labeled `[time, dim]` using the
5	//! standard transformer formula:
6	//!
7	//! ```text
8	//! PE[pos, 2i]   = sin(pos / 10000^(2i / d_model))
9	//! PE[pos, 2i+1] = cos(pos / 10000^(2i / d_model))
10	//! ```
11	//!
12	//! It is a pure function (no parameters, no seed) so two runs with
13	//! the same args produce identical output. Adding it to the output of
14	//! a token embedding works element-wise when shapes match; the
15	//! labeled side propagates `[time, dim]` through the binop.
16	
17	use mlpl_array::{DenseArray, Shape};
18	use mlpl_eval::{Environment, eval_program};
19	use mlpl_parser::{lex, parse};
20	
21	fn run(src: &str, env: &mut Environment) -> DenseArray {
22	    eval_program(&parse(&lex(src).unwrap()).unwrap(), env).unwrap()
23	}
24	
25	#[test]
26	fn sinusoidal_encoding_has_shape_seq_by_d() {
27	    let mut env = Environment::new();
28	    let out = run("sinusoidal_encoding(8, 4)", &mut env);
29	    assert_eq!(out.shape().dims(), &[8, 4]);
30	}
31	
32	#[test]
33	fn sinusoidal_encoding_position_zero_is_alternating_zero_one() {
34	    // At pos=0: sin(0)=0, cos(0)=1 for every (i, parity) pair.
35	    let mut env = Environment::new();
36	    let out = run("sinusoidal_encoding(8, 4)", &mut env);
37	    let row0 = &out.data()[0..4];
38	    assert!((row0[0] - 0.0).abs() < 1e-12, "PE[0,0] = sin(0) = 0");
39	    assert!((row0[1] - 1.0).abs() < 1e-12, "PE[0,1] = cos(0) = 1");
40	    assert!((row0[2] - 0.0).abs() < 1e-12, "PE[0,2] = sin(0) = 0");
41	    assert!((row0[3] - 1.0).abs() < 1e-12, "PE[0,3] = cos(0) = 1");
42	}
43	
44	#[test]
45	fn sinusoidal_encoding_position_one_matches_reference() {
46	    // For d_model=4, i in {0,1}:
47	    //   col 0 (i=0, even): sin(pos / 10000^0)         = sin(pos)
48	    //   col 1 (i=0, odd):  cos(pos / 10000^0)         = cos(pos)
49	    //   col 2 (i=1, even): sin(pos / 10000^(2/4))     = sin(pos / 100)
50	    //   col 3 (i=1, odd):  cos(pos / 10000^(2/4))     = cos(pos / 100)
51	    let mut env = Environment::new();
52	    let out = run("sinusoidal_encoding(8, 4)", &mut env);
53	    let row1 = &out.data()[4..8];
54	    let expected = [
55	        1.0_f64.sin(),
56	        1.0_f64.cos(),
57	        (1.0_f64 / 100.0).sin(),
58	        (1.0_f64 / 100.0).cos(),
59	    ];
60	    for (i, (&got, &want)) in row1.iter().zip(expected.iter()).enumerate() {
61	        assert!(
62	            (got - want).abs() < 1e-12,
63	            "PE[1, {i}] = {got}, expected {want}"
64	        );
65	    }
66	}
67	
68	#[test]
69	fn sinusoidal_encoding_is_deterministic() {
70	    // Pure function: same args, same output across runs.
71	    let mut env = Environment::new();
72	    let a = run("sinusoidal_encoding(16, 8)", &mut env);
73	    let b = run("sinusoidal_encoding(16, 8)", &mut env);
74	    assert_eq!(a.shape(), b.shape());
75	    for (x, y) in a.data().iter().zip(b.data().iter()) {
76	        assert!((x - y).abs() < 1e-15, "determinism: {x} vs {y}");
77	    }
78	}
