80	#[test]
81	fn sinusoidal_encoding_carries_time_dim_labels() {
82	    let mut env = Environment::new();
83	    eval_program(
84	        &parse(&lex("PE = sinusoidal_encoding(4, 6)").unwrap()).unwrap(),
85	        &mut env,
86	    )
87	    .unwrap();
88	    let out = env.get("PE").expect("PE bound");
89	    let labels = out
90	        .labels()
91	        .expect("sinusoidal_encoding output must be labeled");
92	    assert_eq!(labels.len(), 2);
93	    assert_eq!(labels[0].as_deref(), Some("time"));
94	    assert_eq!(labels[1].as_deref(), Some("dim"));
95	}
