97	#[test]
98	fn embed_plus_sinusoidal_encoding_propagates_labels() {
99	    // Pattern documented for adding positional info to a token
100	    // embedding output. With toks of shape [T], `apply(E, toks)`
101	    // returns an unlabeled [T, d_model] array. The sinusoidal table
102	    // carries `[time, dim]` labels; same-shape elementwise add lets
103	    // those labels propagate to the result. For batched [B, T, D]
104	    // workflows the same primitive is applied after flattening
105	    // tokens to [B*T] and tiling positions accordingly.
106	    let mut env = Environment::new();
107	    eval_program(
108	        &parse(
109	            &lex("E = embed(5, 4, 7)\n\
110	                  toks = [0.0, 1.0, 2.0, 3.0]\n\
111	                  emb = apply(E, toks)\n\
112	                  PE = sinusoidal_encoding(4, 4)\n\
113	                  pos_emb = emb + PE")
114	            .unwrap(),
115	        )
116	        .unwrap(),
117	        &mut env,
118	    )
119	    .unwrap();
120	
121	    let out = env.get("pos_emb").expect("pos_emb bound");
122	    assert_eq!(out.shape().dims(), &[4, 4]);
123	    let labels = out.labels().expect("labels propagate from PE");
124	    assert_eq!(labels[0].as_deref(), Some("time"));
125	    assert_eq!(labels[1].as_deref(), Some("dim"));
126	
127	    // Sanity: the result should equal emb + PE element-wise. Pull
128	    // the underlying arrays back out and verify a single position.
129	    let emb = env.get("emb").unwrap();
130	    let pe = env.get("PE").unwrap();
131	    for i in 0..emb.data().len() {
132	        let want = emb.data()[i] + pe.data()[i];
133	        let got = out.data()[i];
134	        assert!((got - want).abs() < 1e-12, "elem {i}: {got} vs {want}");
135	    }
136	}
