69	    let d_model = args[1].data()[0];
70	    if seq_len < 0.0 || seq_len.fract() != 0.0 {
71	        return Err(RuntimeError::InvalidArgument {
72	            func: name.into(),
73	            reason: format!("seq_len must be a non-negative integer, got {seq_len}"),
74	        });
75	    }
76	    if d_model <= 0.0 || d_model.fract() != 0.0 {
77	        return Err(RuntimeError::InvalidArgument {
78	            func: name.into(),
79	            reason: format!("d_model must be a positive integer, got {d_model}"),
80	        });
81	    }
82	    Ok((seq_len as usize, d_model as usize))
83	}
