85	fn builtin_softmax(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
86	    if args.len() != 2 {
87	        return Err(RuntimeError::ArityMismatch {
88	            func: name.into(),
89	            expected: 2,
90	            got: args.len(),
91	        });
92	    }
93	    if args[1].rank() != 0 {
94	        return Err(RuntimeError::InvalidArgument {
95	            func: name.into(),
96	            reason: format!("axis must be scalar, got rank {}", args[1].rank()),
97	        });
98	    }
99	    let a = &args[0];
100	    let axis = args[1].data()[0] as usize;
101	    let dims = a.shape().dims().to_vec();
102	    if axis >= dims.len() {
103	        return Err(RuntimeError::InvalidArgument {
104	            func: name.into(),
105	            reason: format!("axis {axis} out of range for rank {}", dims.len()),
106	        });
107	    }
108	
109	    // Strides for the input shape.
110	    let mut strides = vec![1usize; dims.len()];
111	    for i in (0..dims.len().saturating_sub(1)).rev() {
112	        strides[i] = strides[i + 1] * dims[i + 1];
113	    }
114	    let axis_size = dims[axis];
115	    let axis_stride = strides[axis];
116	
117	    // Group index: flat index with the `axis` coordinate removed.
118	    let mut group_dims = dims.clone();
119	    group_dims.remove(axis);
120	    let group_count: usize = group_dims.iter().product::<usize>().max(1);
121	
122	    // First pass: per-group max for numerical stability.
123	    let mut maxv = vec![f64::NEG_INFINITY; group_count];
124	    for flat in 0..a.elem_count() {
125	        let g = if axis_stride > 1 {
126	            let outer = flat / (axis_size * axis_stride);
127	            let inner = flat % axis_stride;
128	            outer * axis_stride + inner
129	        } else {
130	            flat / axis_size
131	        };
132	        let v = a.data()[flat];
133	        if v > maxv[g] {
134	            maxv[g] = v;
135	        }
136	    }
137	
138	    // Second pass: exponentiate shifted logits and accumulate per-group sums.
139	    let mut out = vec![0.0f64; a.elem_count()];
140	    let mut sums = vec![0.0f64; group_count];
141	    for (flat, slot) in out.iter_mut().enumerate() {
142	        let g = if axis_stride > 1 {
143	            let outer = flat / (axis_size * axis_stride);
144	            let inner = flat % axis_stride;
145	            outer * axis_stride + inner
146	        } else {
147	            flat / axis_size
148	        };
149	        let e = (a.data()[flat] - maxv[g]).exp();
150	        *slot = e;
151	        sums[g] += e;
152	    }
153	
154	    // Third pass: normalize.
155	    for (flat, slot) in out.iter_mut().enumerate() {
156	        let g = if axis_stride > 1 {
157	            let outer = flat / (axis_size * axis_stride);
158	            let inner = flat % axis_stride;
159	            outer * axis_stride + inner
160	        } else {
161	            flat / axis_size
162	        };
163	        *slot /= sums[g];
164	    }
165	
166	    Ok(DenseArray::new(Shape::new(dims), out)?)
167	}
