169	fn builtin_one_hot(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
170	    if args.len() != 2 {
171	        return Err(RuntimeError::ArityMismatch {
172	            func: name.into(),
173	            expected: 2,
174	            got: args.len(),
175	        });
176	    }
177	    if args[0].rank() != 1 {
178	        return Err(RuntimeError::InvalidArgument {
179	            func: name.into(),
180	            reason: format!("labels must be a vector, got rank {}", args[0].rank()),
181	        });
182	    }
183	    if args[1].rank() != 0 {
184	        return Err(RuntimeError::InvalidArgument {
185	            func: name.into(),
186	            reason: "k must be a scalar".into(),
187	        });
188	    }
189	    let labels = args[0].data();
190	    let k = args[1].data()[0] as usize;
191	    let n = labels.len();
192	    let mut data = vec![0.0f64; n * k];
193	    for (i, &lab) in labels.iter().enumerate() {
194	        let j = lab as usize;
195	        if j >= k {
196	            return Err(RuntimeError::InvalidArgument {
197	                func: name.into(),
198	                reason: format!("label {j} out of range for k = {k}"),
199	            });
200	        }
201	        data[i * k + j] = 1.0;
202	    }
203	    Ok(DenseArray::new(Shape::new(vec![n, k]), data)?)
204	}
